const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  HeadingLevel, AlignmentType, BorderStyle, WidthType, ShadingType,
  PageNumber, PageBreak, LevelFormat, Header, Footer, TabStopType,
  TabStopPosition, VerticalAlign, UnderlineType
} = require('docx');
const fs = require('fs');

const ACCENT   = "1F3A6E"; // deep navy
const ACCENT2  = "C0392B"; // red
const GOLD     = "C8860A"; // amber
const LIGHT_BG = "EEF3FB"; // light blue
const GREEN_BG = "E8F5E9";
const RED_BG   = "FDECEA";
const GRAY_BG  = "F5F5F5";
const WHITE    = "FFFFFF";
const DARK     = "1A1A1A";

const border = { style: BorderStyle.SINGLE, size: 1, color: "CCCCCC" };
const borders = { top: border, bottom: border, left: border, right: border };
const noBorder = { style: BorderStyle.NONE, size: 0, color: "FFFFFF" };
const noBorders = { top: noBorder, bottom: noBorder, left: noBorder, right: noBorder };

const sp = (before = 0, after = 0) => ({ spacing: { before, after } });

// ─── Helpers ───────────────────────────────────────────────────────────────

function h1(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_1,
    children: [new TextRun({ text, bold: true, size: 36, color: ACCENT, font: "Arial" })],
    spacing: { before: 480, after: 200 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 6, color: ACCENT, space: 1 } }
  });
}

function h2(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_2,
    children: [new TextRun({ text, bold: true, size: 28, color: ACCENT, font: "Arial" })],
    spacing: { before: 320, after: 120 }
  });
}

function h3(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_3,
    children: [new TextRun({ text, bold: true, size: 24, color: ACCENT2, font: "Arial" })],
    spacing: { before: 240, after: 80 }
  });
}

function para(text, opts = {}) {
  return new Paragraph({
    children: [new TextRun({ text, size: 22, font: "Arial", color: DARK, ...opts })],
    spacing: { before: 60, after: 100 },
    alignment: AlignmentType.JUSTIFIED
  });
}

function bold(text) {
  return new TextRun({ text, bold: true, size: 22, font: "Arial", color: DARK });
}

function code(text) {
  return new TextRun({ text, font: "Courier New", size: 18, color: "2C3E50" });
}

function bullet(text, level = 0, ref = "bullets") {
  const [head, ...rest] = text.split(/:\s(.+)/);
  const children = rest.length
    ? [new TextRun({ text: head + ": ", bold: true, size: 22, font: "Arial", color: DARK }),
       new TextRun({ text: rest.join(""), size: 22, font: "Arial", color: DARK })]
    : [new TextRun({ text, size: 22, font: "Arial", color: DARK })];
  return new Paragraph({
    numbering: { reference: ref, level },
    children,
    spacing: { before: 40, after: 40 }
  });
}

function numbered(text, ref = "numbers") {
  return new Paragraph({
    numbering: { reference: ref, level: 0 },
    children: [new TextRun({ text, size: 22, font: "Arial", color: DARK })],
    spacing: { before: 40, after: 40 }
  });
}

function callout(label, text, fillColor = LIGHT_BG, labelColor = ACCENT) {
  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [9360],
    rows: [new TableRow({ children: [new TableCell({
      borders: { ...noBorders, left: { style: BorderStyle.SINGLE, size: 18, color: labelColor } },
      shading: { fill: fillColor, type: ShadingType.CLEAR },
      margins: { top: 120, bottom: 120, left: 240, right: 240 },
      width: { size: 9360, type: WidthType.DXA },
      children: [
        new Paragraph({ children: [new TextRun({ text: label, bold: true, size: 20, color: labelColor, font: "Arial" })], spacing: { before: 0, after: 60 } }),
        new Paragraph({ children: [new TextRun({ text, size: 20, font: "Arial", color: DARK })], alignment: AlignmentType.JUSTIFIED, spacing: { before: 0, after: 0 } })
      ]
    })]})],
    margins: { top: 160, bottom: 160 }
  });
}

function divider() {
  return new Paragraph({
    border: { bottom: { style: BorderStyle.SINGLE, size: 4, color: "DDDDDD", space: 1 } },
    spacing: { before: 240, after: 240 },
    children: []
  });
}

function space(n = 1) {
  return [...Array(n)].map(() => new Paragraph({ children: [], spacing: { before: 60, after: 60 } }));
}

function tableRow(cells, header = false) {
  const colW = [2800, 2000, 2000, 2560];
  return new TableRow({
    tableHeader: header,
    children: cells.map((text, i) => new TableCell({
      borders,
      width: { size: colW[i] || 2340, type: WidthType.DXA },
      shading: { fill: header ? ACCENT : (i === 0 ? GRAY_BG : WHITE), type: ShadingType.CLEAR },
      margins: { top: 80, bottom: 80, left: 120, right: 120 },
      verticalAlign: VerticalAlign.CENTER,
      children: [new Paragraph({ children: [new TextRun({ text, bold: header, size: 20, font: "Arial", color: header ? WHITE : DARK })], alignment: AlignmentType.LEFT })]
    }))
  });
}

function twoColTable(rows, col1W = 3000, col2W = 6360) {
  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [col1W, col2W],
    rows: rows.map(([a, b], i) => new TableRow({
      children: [
        new TableCell({ borders, width: { size: col1W, type: WidthType.DXA }, shading: { fill: i % 2 === 0 ? LIGHT_BG : WHITE, type: ShadingType.CLEAR }, margins: { top: 80, bottom: 80, left: 120, right: 120 }, children: [new Paragraph({ children: [new TextRun({ text: a, bold: true, size: 20, font: "Arial", color: ACCENT })]})] }),
        new TableCell({ borders, width: { size: col2W, type: WidthType.DXA }, shading: { fill: i % 2 === 0 ? LIGHT_BG : WHITE, type: ShadingType.CLEAR }, margins: { top: 80, bottom: 80, left: 120, right: 120 }, children: [new Paragraph({ children: [new TextRun({ text: b, size: 20, font: "Arial", color: DARK })]})] })
      ]
    }))
  });
}

// ─── Cover Page ─────────────────────────────────────────────────────────────

const coverChildren = [
  new Paragraph({ children: [new TextRun({ text: "PROJECT TECHNICAL DOCUMENTATION", size: 18, font: "Arial", color: ACCENT, bold: true, characterSpacing: 80 })], spacing: { before: 0, after: 480 } }),

  new Paragraph({ children: [new TextRun({ text: "Cold-Start", size: 72, font: "Arial", bold: true, color: ACCENT })], spacing: { before: 0, after: 0 } }),
  new Paragraph({ children: [new TextRun({ text: "StyleVector", size: 72, font: "Arial", bold: true, color: ACCENT2 })], spacing: { before: 0, after: 0 } }),

  new Paragraph({ children: [new TextRun({ text: "Personalized Headline Generation for Journalists with Sparse Writing History", size: 26, font: "Arial", color: "555555" })], spacing: { before: 240, after: 480 } }),

  new Paragraph({ border: { bottom: { style: BorderStyle.SINGLE, size: 4, color: ACCENT, space: 1 } }, children: [], spacing: { before: 0, after: 480 } }),

  new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [3120, 3120, 3120],
    rows: [new TableRow({ children: [
      new TableCell({ borders: noBorders, width: { size: 3120, type: WidthType.DXA }, children: [
        new Paragraph({ children: [new TextRun({ text: "STUDENT", size: 16, font: "Arial", color: "999999", bold: true, characterSpacing: 60 })], spacing: { before: 0, after: 60 } }),
        new Paragraph({ children: [new TextRun({ text: "Dharmik Mistry", size: 22, font: "Arial", bold: true, color: DARK })], spacing: { before: 0, after: 0 } }),
        new Paragraph({ children: [new TextRun({ text: "202311039 · M.Tech ICT (ML)", size: 18, font: "Arial", color: "666666" })], spacing: { before: 0, after: 0 } })
      ]}),
      new TableCell({ borders: noBorders, width: { size: 3120, type: WidthType.DXA }, children: [
        new Paragraph({ children: [new TextRun({ text: "INSTITUTION", size: 16, font: "Arial", color: "999999", bold: true, characterSpacing: 60 })], spacing: { before: 0, after: 60 } }),
        new Paragraph({ children: [new TextRun({ text: "DA-IICT, Gandhinagar", size: 22, font: "Arial", bold: true, color: DARK })], spacing: { before: 0, after: 0 } }),
        new Paragraph({ children: [new TextRun({ text: "MTech Batch 2025 — Sem 2", size: 18, font: "Arial", color: "666666" })], spacing: { before: 0, after: 0 } })
      ]}),
      new TableCell({ borders: noBorders, width: { size: 3120, type: WidthType.DXA }, children: [
        new Paragraph({ children: [new TextRun({ text: "VERSION", size: 16, font: "Arial", color: "999999", bold: true, characterSpacing: 60 })], spacing: { before: 0, after: 60 } }),
        new Paragraph({ children: [new TextRun({ text: "v1.0 — March 2026", size: 22, font: "Arial", bold: true, color: DARK })], spacing: { before: 0, after: 0 } }),
        new Paragraph({ children: [new TextRun({ text: "6-Week Execution Plan", size: 18, font: "Arial", color: "666666" })], spacing: { before: 0, after: 0 } })
      ]})
    ]})]
  }),

  new Paragraph({ children: [], spacing: { before: 480, after: 0 } }),

  new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [9360],
    rows: [new TableRow({ children: [new TableCell({
      borders: { ...noBorders, left: { style: BorderStyle.SINGLE, size: 24, color: GOLD } },
      shading: { fill: "FFF8E1", type: ShadingType.CLEAR },
      margins: { top: 160, bottom: 160, left: 240, right: 240 },
      width: { size: 9360, type: WidthType.DXA },
      children: [
        new Paragraph({ children: [new TextRun({ text: "NOVEL CONTRIBUTION — VERIFIED ORIGINAL", bold: true, size: 20, font: "Arial", color: GOLD })], spacing: { before: 0, after: 80 } }),
        new Paragraph({ children: [new TextRun({ text: "Cluster-Centroid Cold-Start Interpolation for StyleVector: No prior work applies K-means clustering of rich-author style vectors in LLM activation space to initialize sparse-author vectors via alpha-weighted interpolation. The specific combination of StyleVector + cold-start cluster interpolation + Indian journalism domain is unimplemented in existing literature.", size: 20, font: "Arial", color: DARK })], alignment: AlignmentType.JUSTIFIED, spacing: { before: 0, after: 0 } })
      ]
    })]})],
  }),

  new Paragraph({ children: [new PageBreak()] })
];

// ─── Build full document ─────────────────────────────────────────────────────

const docChildren = [
  ...coverChildren,

  // ──────────────────────────────────────────────────
  // SECTION 1: PROBLEM STATEMENT
  // ──────────────────────────────────────────────────
  h1("1. Problem Statement"),
  para("The modern newsroom produces an enormous volume of content, and the headline is the single most consequential element of any article. A headline determines whether a reader clicks, shares, or scrolls past. Beyond click behaviour, headlines carry a journalist's identity — their tone, vocabulary, sentence rhythm, and editorial stance. An experienced reader of The Hindu can often identify a Suhasini Haidar headline by style alone, before seeing the byline."),
  para("The problem this project addresses is: how do you automatically generate a news headline that is both accurate to the article content AND faithful to a specific journalist's writing style?"),

  h2("1.1 Why Existing Solutions Fail"),
  para("Three paradigms exist for personalised text generation, and all three have significant limitations:"),

  twoColTable([
    ["Supervised Fine-Tuning (SFT / PEFT)", "Per-user LoRA adapter requires 17MB of stored weights per journalist and expensive retraining whenever new data arrives. Does not scale to hundreds of journalists."],
    ["Retrieval-Augmented Generation (RAG)", "Retrieves k similar past articles and provides them as context. Suffers from content-style entanglement — it retrieves topically similar articles, not stylistically similar ones. Fails for sparse authors who have too few articles to retrieve meaningfully."],
    ["StyleVector (Huang et al., 2025)", "Extracts a single 4096-dimensional style vector per user via contrastive activation analysis. Requires 50-287 articles per user to compute a reliable vector. The paper explicitly admits it degrades for sparse users. No solution for the cold-start problem is proposed."]
  ], 2800, 6560),

  ...space(),
  h2("1.2 The Gap This Project Fills"),
  callout("The Specific Research Gap", "The StyleVector paper (arXiv:2503.05213, March 2025) explicitly states in its limitations section that sparse-user performance degrades significantly and that cold-start initialisation is left as future work. No subsequent paper has applied cluster-centroid interpolation in LLM activation space to resolve this gap specifically for StyleVector. This project fills that gap with a measurable, comparable, and deployable contribution.", LIGHT_BG, ACCENT),

  ...space(),
  para("Beyond the research gap, this project addresses a real social need: democratising stylistic assistance for journalists. Junior journalists, freelancers, and regional reporters — who often have fewer published articles — are exactly the users who would benefit most from automated headline assistance. They are also exactly the users StyleVector fails for. This project is built for them."),

  new Paragraph({ children: [new PageBreak()] }),

  // ──────────────────────────────────────────────────
  // SECTION 2: NOVEL CONTRIBUTION
  // ──────────────────────────────────────────────────
  h1("2. Novel Contribution"),
  h2("2.1 Novelty Verification"),
  para("A thorough literature search was conducted across arXiv, ACL Anthology, ACM DL, and Semantic Scholar. Key papers reviewed:"),

  twoColTable([
    ["StyleVector (2503.05213, 2025)", "The base paper this work extends. Proposes contrastive activation steering for personalised generation. Explicitly leaves cold-start as future work."],
    ["GraSPeR (2602.21219, 2026)", "Addresses sparse personalisation via graph-based reasoning for review generation. Does NOT use activation steering or style vectors. Different method and domain entirely."],
    ["PHG-DIF (CIKM 2025)", "Personalized headline generation via click-noise denoising. Relies on user click behaviour logs (Microsoft News). Explicitly excludes cold-start users from scope."],
    ["PENS Benchmark (ACL 2021)", "Benchmark dataset for personalized headline generation. Reader-side preference, not journalist-style generation. No sparse-author handling."],
    ["GTP (TACL 2023)", "Decoupled generation and personalisation for headlines. Uses predefined style control codes. Does not handle the cold-start case."]
  ], 3000, 6360),

  ...space(),
  callout("Novelty Verdict", "The specific combination of: (1) StyleVector's contrastive activation extraction, (2) K-means clustering of rich-author style vectors in LLM activation space, and (3) alpha-weighted centroid interpolation for sparse-author cold-start initialisation — has NOT been implemented or published. The contribution is original.", GREEN_BG, "2E7D32"),

  ...space(),
  h2("2.2 The Cold-Start Contribution — Precise Definition"),
  para("When a journalist has fewer than 20 published articles, the naive StyleVector computation produces a noisy, unreliable vector — too few (article, headline) pairs exist to average out content-specific noise and isolate the style signal."),
  para("The proposed method — Cold-Start StyleVector — addresses this as follows:"),

  new Paragraph({ children: [new TextRun({ text: "Step 1 — Cluster Rich Authors:", bold: true, size: 22, font: "Arial", color: ACCENT })], spacing: { before: 120, after: 40 } }),
  para("After computing reliable style vectors for all rich authors (50+ articles each), apply K-means clustering to group them into K style clusters. Each centroid represents a prototypical journalistic writing style — for example: 'terse news-wire', 'analytical long-form', 'conversational sports', 'political commentary'. Optimal K is selected by maximising silhouette score over K = 5 to 20."),

  new Paragraph({ children: [new TextRun({ text: "Step 2 — Initialise Sparse Authors:", bold: true, size: 22, font: "Arial", color: ACCENT })], spacing: { before: 120, after: 40 } }),
  para("For a sparse journalist with only 5-20 articles, compute their raw (noisy) style vector using the same contrastive activation method. Normalise it, find the nearest cluster centroid by cosine similarity, then interpolate:"),

  new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [9360],
    rows: [new TableRow({ children: [new TableCell({
      borders: noBorders,
      shading: { fill: "F0EDE6", type: ShadingType.CLEAR },
      margins: { top: 120, bottom: 120, left: 240, right: 240 },
      width: { size: 9360, type: WidthType.DXA },
      children: [
        new Paragraph({ children: [new TextRun({ text: "v_cold = alpha * v_centroid  +  (1 - alpha) * v_sparse", font: "Courier New", size: 22, color: ACCENT2, bold: true })], alignment: AlignmentType.CENTER, spacing: { before: 0, after: 0 } })
      ]
    })]})],
  }),

  ...space(),
  para("Where alpha is a hyperparameter swept from 0.2 to 0.8 on a validation set. When alpha = 1.0, the sparse author is assigned entirely to the nearest cluster (maximum smoothing). When alpha = 0.0, the raw sparse vector is used unchanged (identical to vanilla StyleVector). The optimal alpha trades off: how much do we trust the noisy sparse vector vs. the cluster prior?"),

  new Paragraph({ children: [new TextRun({ text: "Step 3 — Use Cold-Start Vector at Inference:", bold: true, size: 22, font: "Arial", color: ACCENT })], spacing: { before: 120, after: 40 } }),
  para("Replace the sparse author's noisy vector with v_cold in the activation steering step. All inference machinery is identical to the original StyleVector method. The cold-start module is a pure pre-processing addition."),

  h2("2.3 Why This Works — Intuition"),
  para("Journalistic writing styles are not randomly distributed across 4096-dimensional activation space — they cluster by genre, register, and outlet. A political correspondent from any publication likely steers in a similar direction in activation space compared to a sports reporter. The cluster centroid encodes this prior knowledge learned from rich authors. For a new journalist with only 8 articles, their sparse vector points roughly in the right direction but is noisy. Blending with the nearest centroid de-noises it using population-level knowledge."),

  new Paragraph({ children: [new PageBreak()] }),

  // ──────────────────────────────────────────────────
  // SECTION 3: STYLEVECTOR PAPER — HOW IT WORKS
  // ──────────────────────────────────────────────────
  h1("3. StyleVector — Paper Explanation"),
  para("Before describing the implementation, it is essential to understand precisely what the StyleVector paper proposes. Everything in this project builds on top of this foundation."),

  h2("3.1 Core Insight"),
  para("Large language models maintain internal representations of text in high-dimensional vector spaces at each transformer layer. These hidden state vectors encode not just the semantic meaning of text, but also its stylistic properties — tone, formality, sentence rhythm, vocabulary register."),
  para("The key insight of StyleVector: if you show the model the same content written in two different styles (a journalist's actual headline vs. a generic neutral headline), the difference in hidden-state activations at a specific layer is a direction in activation space that corresponds to that journalist's style. Average this difference over many articles, and you get a stable style vector."),

  h2("3.2 Three-Stage Pipeline"),

  h3("Stage A — Style-Agnostic Response Generation"),
  para("For every article in a journalist's history, generate a 'generic' headline using any general-purpose LLM (Gemini Flash in our implementation). This headline is content-accurate but stylistically neutral — it would be acceptable from any wire service."),
  para("This gives us for each journalist u and article i: a pair (y_i_real, y_i_agnostic) — the real headline and the generic headline for the same content."),

  h3("Stage B — Style Vector Extraction via Contrastive Activation Analysis"),
  para("Load LLaMA-2-7B and, for each article-headline pair, extract the hidden state at a chosen transformer layer L (the last token position):"),
  para("h_positive = hidden_state_L(article_content + y_i_real)"),
  para("h_negative = hidden_state_L(article_content + y_i_agnostic)"),
  para("Difference: d_i = h_positive - h_negative"),
  para("This difference isolates the style signal from the content signal — since both headlines are about the same article, the content information largely cancels, leaving the style direction."),
  para("The journalist's style vector is the mean of all differences: v_u = (1/N) * sum(d_i for i in 1..N)"),
  para("This vector is tiny (4096 floats = 16KB) and is computed once. It captures the journalist's style permanently."),

  h3("Stage C — Activation Steering at Inference"),
  para("When generating a headline for a new article by journalist u, inject the style vector v_u into the model's hidden states at layer L during the forward pass:"),
  para("h_steered = h_original + alpha_steer * v_u"),
  para("This nudges the generation in the direction of the journalist's style without modifying any model weights. The effect is that the model produces text that sounds like that journalist wrote it."),

  h2("3.3 Why QLoRA Fine-Tuning Precedes This (Stage 1)"),
  para("The base LLaMA-2-7B-chat model is a general-purpose assistant, not a headline generator. If you extract style vectors from a model that does not understand the headline generation task well, the contrastive difference captures a mix of task-confusion noise and style signal."),
  para("By first fine-tuning LLaMA-2-7B on a headline generation task using QLoRA, the model becomes a competent generic headline generator. Now when you compute the contrastive difference (real headline vs. generic headline from this tuned model), the content signal is cleaner and the style signal is more isolated. This is a justified improvement over the original paper's use of the base chat model, and it constitutes the 'training' component that satisfies the course rubric."),

  new Paragraph({ children: [new PageBreak()] }),

  // ──────────────────────────────────────────────────
  // SECTION 4: DATASET
  // ──────────────────────────────────────────────────
  h1("4. Dataset Strategy"),

  h2("4.1 Primary Dataset — All The News V2"),
  para("All The News V2 is a Kaggle dataset containing approximately 2.7 million English-language news articles from over 50 US publications including NYT, Reuters, Guardian, NPR, The Atlantic, and BuzzFeed. It contains individual author bylines, publication dates, full article bodies, and headlines."),
  para("This dataset is used as the primary source for: (a) QLoRA fine-tuning of LLaMA-2-7B on headline generation, and (b) rich-author style vector computation and clustering."),

  twoColTable([
    ["Filtering", "Remove desk accounts, wire services (AP, Reuters), and any entry without a named individual author. Keep only authors with 80+ articles published across 3+ months."],
    ["Scale target", "200 named individual Western journalists, each with 80-150 articles. Approximately 20,000-40,000 articles for SFT training, 40,000-80,000 for style vector computation."],
    ["Split", "For each rich author, chronological split: first 70% train, next 15% validation, last 15% test."]
  ], 2400, 6960),

  ...space(),
  h2("4.2 Secondary Dataset — Indian Journalism (TOI + HT)"),
  para("A custom-scraped dataset from Times of India and Hindustan Times, constructed from named individual journalists with profile pages on each publication's website."),
  callout("Current Dataset Status", "The existing dataset.json contains 1,019 articles from TOI only, all from Times of India, with 994/1,019 articles having date: Unknown, and only 2 usable named individual journalists (Sehjal Gupta: 52 articles, Mahima Roy: 44 articles). The remainder are desk accounts. This dataset must be fully rebuilt with mandatory date extraction.", RED_BG, ACCENT2),

  ...space(),

  twoColTable([
