  para("All evaluation follows the original StyleVector paper's protocol to ensure direct comparability. The paper uses LaMP and LongLaMP benchmarks; this project constructs an equivalent evaluation on its own dataset."),

  h2("9.1 Metrics"),
  twoColTable([
    ["ROUGE-L", "Measures longest common subsequence between generated and reference headline. Captures word overlap at the sequence level. Widely used in summarisation and headline generation."],
    ["METEOR", "Accounts for synonyms, stemming, and paraphrases. Better than ROUGE for capturing meaning-equivalent expressions. Used in the original paper."],
    ["BERTScore", "Uses BERT embeddings to compute semantic similarity between generated and reference headline. Captures meaning beyond surface lexical overlap."],
    ["Style Consistency Score (Original)", "Train a linear SVM on rich-author style vectors as a journalist classifier. Apply to embeddings of generated headlines. Percentage correctly attributed to their target journalist. This metric is not in the original paper and is our additional evaluation contribution."]
  ], 2800, 6560),

  ...space(),
  h2("9.2 Four-Method Comparison"),
