  ...space(),
  twoColTable([
    ["Question 1: Does the rubric require actual model training?", "If YES: QLoRA fine-tuning in Week 3 is mandatory and adds significant compute overhead. If NO: Skip Stage 1. Use base LLaMA-2-7B-chat directly. This frees up 1-1.5 weeks of compute time for a solo 6-week project."],
    ["Question 2: What counts as deployed?", "If permanently accessible URL is required: Stage 3A (HF Spaces + Vercel) satisfies this. If live demo during presentation is sufficient: Stage 3B (Colab + ngrok) may suffice. Knowing this changes how much effort goes into Week 6."]
  ], 3400, 5960),

  ...space(),
  h2("10.1 Plan Variants"),
  para("If faculty confirms training IS required: execute the plan as written. Week 3 = QLoRA. Activation extraction in Week 4 uses the fine-tuned model."),
  para("If faculty confirms training is NOT required: skip Week 3. Move All The News filtering to Week 2. Begin activation extraction in Week 3 using base LLaMA-2-7B-chat. This gives one additional week of buffer — use it on evaluation depth and frontend polish."),

  divider(),

  new Paragraph({ children: [new TextRun({ text: "Cold-Start StyleVector  ·  Technical Documentation v1.0  ·  DA-IICT M.Tech Project 2026  ·  Dharmik Mistry", size: 16, font: "Arial", color: "999999" })], alignment: AlignmentType.CENTER, spacing: { before: 240, after: 0 } })
];

// ─── Document Assembly ───────────────────────────────────────────────────────

const doc = new Document({
  numbering: {
    config: [
      { reference: "bullets", levels: [
        { level: 0, format: LevelFormat.BULLET, text: "\u2022", alignment: AlignmentType.LEFT, style: { paragraph: { indent: { left: 720, hanging: 360 } } } },
        { level: 1, format: LevelFormat.BULLET, text: "\u25E6", alignment: AlignmentType.LEFT, style: { paragraph: { indent: { left: 1080, hanging: 360 } } } }
      ]},
      { reference: "numbers", levels: [
        { level: 0, format: LevelFormat.DECIMAL, text: "%1.", alignment: AlignmentType.LEFT, style: { paragraph: { indent: { left: 720, hanging: 360 } } } }
      ]}
    ]
  },
  styles: {
    default: { document: { run: { font: "Arial", size: 22 } } },
    paragraphStyles: [
      { id: "Heading1", name: "Heading 1", basedOn: "Normal", next: "Normal", quickFormat: true, run: { size: 36, bold: true, font: "Arial", color: ACCENT }, paragraph: { spacing: { before: 480, after: 200 }, outlineLevel: 0 } },
      { id: "Heading2", name: "Heading 2", basedOn: "Normal", next: "Normal", quickFormat: true, run: { size: 28, bold: true, font: "Arial", color: ACCENT }, paragraph: { spacing: { before: 320, after: 120 }, outlineLevel: 1 } },
      { id: "Heading3", name: "Heading 3", basedOn: "Normal", next: "Normal", quickFormat: true, run: { size: 24, bold: true, font: "Arial", color: ACCENT2 }, paragraph: { spacing: { before: 240, after: 80 }, outlineLevel: 2 } },
    ]
  },
  sections: [{
    properties: {
      page: {
        size: { width: 12240, height: 15840 },
        margin: { top: 1440, right: 1260, bottom: 1440, left: 1260 }
      }
    },
    headers: {
      default: new Header({ children: [new Paragraph({ children: [
        new TextRun({ text: "Cold-Start StyleVector  ·  Project Documentation", size: 16, font: "Arial", color: "999999" }),
        new TextRun({ children: [new PageNumber()], size: 16, font: "Arial", color: "999999" })
      ], border: { bottom: { style: BorderStyle.SINGLE, size: 4, color: "DDDDDD", space: 1 } }, alignment: AlignmentType.RIGHT })] })
    },
    children: docChildren
  }]
});

Packer.toBuffer(doc).then(buf => {
  fs.writeFileSync("/home/claude/cold_start_stylevector_documentation.docx", buf);
  console.log("Done");
});

